  const pendingMessageRef = useRef<string | null>(null);
  const hasSentPendingRef = useRef(false);

  const { sendMessage, messages, isConnected, createConversation: createNewConversation } = useAgentChat(AGENT_ID, conversationId);

  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  // Send the pending initial message once the stream is connected
  useEffect(() => {
    if (isConnected && conversationId && pendingMessageRef.current && !hasSentPendingRef.current) {
      hasSentPendingRef.current = true;
      const msg = pendingMessageRef.current;
      pendingMessageRef.current = null;
      sendMessage(msg);
    }
  }, [isConnected, conversationId, sendMessage]);

  const handleStart = async (initialMessage?: string) => {
    if (isStarting) return;
    setIsStarting(true);
    // Reset pending state for new conversation
    hasSentPendingRef.current = false;
    pendingMessageRef.current = initialMessage ?? null;
    try {
      const { conversationId: newId } = await createConversation(AGENT_ID);
      setConversationId(newId);
    } catch (e) {
      console.error(e);
      pendingMessageRef.current = null;
    } finally {
      setIsStarting(false);
    }
  };

  const handleSend = () => {
    const text = input.trim();
    if (!text || !conversationId) return;
    sendMessage(text);
    setInput('');
    inputRef.current?.focus();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleNewConversation = async () => {
    hasSentPendingRef.current = false;
    pendingMessageRef.current = null;
    const newId = await createNewConversation();
    setConversationId(newId);
  };

  // Welcome screen
  if (!conversationId) {
    return (
      <div className="h-full flex flex-col items-center justify-center px-6 py-12">
        <div className="w-full max-w-lg text-center space-y-8">
          {/* Avatar */}
          <div className="relative mx-auto w-fit">
            <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-violet-500 via-purple-600 to-cyan-500 flex items-center justify-center shadow-xl shadow-violet-500/30">
              <Bot size={36} className="text-white" />
            </div>
            <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-emerald-400 rounded-full border-2 border-[#0a0a0f] shadow-sm shadow-emerald-400/50" />
          </div>

          <div>
            <h2 className="text-2xl font-bold text-white mb-2">Support Agent</h2>
            <p className="text-white/50 text-sm leading-relaxed max-w-sm mx-auto">
              Hi! I'm your AI support agent, trained on our knowledge base to resolve issues instantly. How can I help?
            </p>
          </div>

          {/* Starter suggestions */}
          <div className="grid grid-cols-2 gap-2">
            {starters.map((s) => (
              <button
                key={s.title}
                onClick={() => handleStart(s.prompt)}
                disabled={isStarting}
                className="group text-left px-4 py-3 rounded-xl border border-white/[0.08] bg-white/[0.03] hover:bg-white/[0.07] hover:border-white/[0.15] transition-all duration-200 disabled:opacity-50"
              >
                <div className="flex items-center justify-between">
                  <span className="text-xs font-medium text-white/70 group-hover:text-white transition-colors">{s.title}</span>
                  <ChevronRight size={12} className="text-white/30 group-hover:text-white/60 transition-colors" />
                </div>
              </button>
            ))}
          </div>

          <button
            onClick={() => handleStart()}
            disabled={isStarting}
            className="flex items-center gap-2 mx-auto px-6 py-3 rounded-xl bg-gradient-to-r from-violet-600 to-cyan-600 text-white text-sm font-medium hover:opacity-90 transition-opacity shadow-lg shadow-violet-500/25 disabled:opacity-60"
          >
            {isStarting ? (
              <Loader2 size={15} className="animate-spin" />
            ) : (
              <Sparkles size={15} />
            )}
            {isStarting ? 'Connecting...' : 'Start a conversation'}
          </button>
        </div>
      </div>
    );
  }

  const isLoading = messages.length > 0 && messages[messages.length - 1]?.role === 'user';

  return (
    <div className="h-full flex flex-col">
      {/* Chat header */}
      <div className="flex items-center justify-between px-5 py-3 border-b border-white/[0.06] bg-black/20">
        <div className="flex items-center gap-2.5">
          <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-violet-500 to-cyan-500 flex items-center justify-center">
            <Bot size={13} className="text-white" />
          </div>
          <div>
            <p className="text-xs font-medium text-white">Support Agent</p>
            <p className="text-[10px] text-emerald-400">{isConnected ? 'Connected' : 'Connecting...'}</p>
          </div>
        </div>
        <button
          onClick={handleNewConversation}
          className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-white/[0.08] bg-white/[0.03] hover:bg-white/[0.07] text-white/50 hover:text-white/80 text-xs transition-all"
        >
          <Plus size={11} />
          New chat
        </button>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto px-4 py-5 space-y-5">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={cn('flex gap-3', msg.role === 'user' ? 'justify-end' : 'justify-start')}
          >
            {msg.role === 'assistant' && (
              <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-violet-500 to-cyan-500 flex items-center justify-center shrink-0 mt-0.5">
                <Bot size={13} className="text-white" />
              </div>
            )}

            <div className={cn('max-w-[75%] space-y-1', msg.role === 'user' ? 'items-end' : 'items-start')}>
              {msg.role === 'assistant' && msg.toolCalls && msg.toolCalls.length > 0 && (
                <div className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-amber-500/10 border border-amber-500/20 text-[10px] text-amber-400 w-fit mb-1">
                  <Wrench size={10} />
                  Using {msg.toolCalls.length} tool{msg.toolCalls.length > 1 ? 's' : ''}
                </div>
              )}

              <div
                className={cn(
                  'px-4 py-3 rounded-2xl text-sm leading-relaxed',
                  msg.role === 'user'
                    ? 'bg-gradient-to-br from-violet-600 to-violet-700 text-white rounded-tr-sm shadow-lg shadow-violet-500/20'
                    : 'bg-white/[0.06] border border-white/[0.08] text-white/90 rounded-tl-sm'
                )}
              >
                {msg.role === 'assistant' ? (
                  <div className="prose prose-invert prose-sm max-w-none prose-p:my-1 prose-ul:my-1 prose-li:my-0.5">
                    <ReactMarkdown>{msg.content || (isLoading ? '' : '...')}</ReactMarkdown>
                  </div>
                ) : (
                  <span>{msg.content}</span>
                )}
              </div>
            </div>

            {msg.role === 'user' && (
              <div className="w-7 h-7 rounded-lg bg-white/[0.08] border border-white/[0.1] flex items-center justify-center shrink-0 mt-0.5">
                <User size={13} className="text-white/60" />
              </div>
            )}
          </div>
        ))}

        {isLoading && (
          <div className="flex gap-3 justify-start">
            <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-violet-500 to-cyan-500 flex items-center justify-center shrink-0">
              <Bot size={13} className="text-white" />
            </div>
            <div className="px-4 py-3 rounded-2xl rounded-tl-sm bg-white/[0.06] border border-white/[0.08]">
              <div className="flex gap-1 items-center h-4">
                <div className="w-1.5 h-1.5 rounded-full bg-white/40 animate-bounce [animation-delay:0ms]" />
                <div className="w-1.5 h-1.5 rounded-full bg-white/40 animate-bounce [animation-delay:150ms]" />
                <div className="w-1.5 h-1.5 rounded-full bg-white/40 animate-bounce [animation-delay:300ms]" />
              </div>
            </div>
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="px-4 pb-4 pt-2 border-t border-white/[0.06] bg-black/20">
        <div className="flex items-end gap-2 px-3 py-2 rounded-xl border border-white/[0.1] bg-white/[0.04] focus-within:border-violet-500/40 focus-within:bg-white/[0.06] transition-all">
          <textarea
            ref={inputRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Describe your issue..."
            rows={1}
            className="flex-1 bg-transparent text-sm text-white placeholder-white/30 resize-none outline-none min-h-[24px] max-h-32 py-1 leading-6"
            style={{ height: 'auto' }}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || !conversationId}
            className="w-8 h-8 rounded-lg bg-gradient-to-br from-violet-600 to-cyan-600 flex items-center justify-center shrink-0 hover:opacity-90 disabled:opacity-30 transition-all shadow-sm shadow-violet-500/30"
          >
            <Send size={13} className="text-white" />
          </button>
        </div>
        <p className="text-[10px] text-white/20 text-center mt-2">Press Enter to send · Shift+Enter for new line</p>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import { cn } from '@/lib/utils';
import {
  Inbox, Plus, X, Send, Loader2, AlertTriangle, Clock,
  CheckCircle, Circle, ArrowUp, ChevronRight, RefreshCw,
  Mail, Tag, Zap
} from 'lucide-react';

interface TicketNode {
  id: string;
  parentId: string | null;
  fieldValues: {
    '/text'?: string;
    '/attributes/@tstat'?: string;
    '/attributes/@tpri'?: string;
    '/attributes/@temail'?: string;
    '/attributes/@tcat'?: string;
    '/attributes/note'?: string;
  };
}

interface Ticket {
  id: string;
  title: string;
  status: string;
  priority: string;
  email: string;
  category: string;
  note: string;
}

const STATUS_CONFIG: Record<string, { label: string; color: string; icon: React.FC<{size?: number}> }> = {
  open: { label: 'Open', color: 'text-blue-400 bg-blue-400/10 border-blue-400/20', icon: Circle },
  in_progress: { label: 'In Progress', color: 'text-amber-400 bg-amber-400/10 border-amber-400/20', icon: Clock },
  resolved: { label: 'Resolved', color: 'text-emerald-400 bg-emerald-400/10 border-emerald-400/20', icon: CheckCircle },
  escalated: { label: 'Escalated', color: 'text-red-400 bg-red-400/10 border-red-400/20', icon: AlertTriangle },
  closed: { label: 'Closed', color: 'text-white/30 bg-white/5 border-white/10', icon: X },
};

const PRIORITY_CONFIG: Record<string, { label: string; color: string }> = {
  low: { label: 'Low', color: 'text-emerald-400' },
  medium: { label: 'Medium', color: 'text-amber-400' },
  high: { label: 'High', color: 'text-orange-400' },
  critical: { label: 'Critical', color: 'text-red-400' },
};

const CAT_LABELS: Record<string, string> = {
  billing: 'Billing', technical: 'Technical', account: 'Account',
  general: 'General', shipping: 'Shipping'
};

function parseTickets(nodes: TicketNode[]): Ticket[] {
  return nodes
    .filter((n) => n.parentId === null && n.fieldValues['/text'])
    .map((n) => ({
      id: n.id,
      title: n.fieldValues['/text'] || 'Untitled',
      status: n.fieldValues['/attributes/@tstat'] || 'open',
      priority: n.fieldValues['/attributes/@tpri'] || 'medium',
      email: n.fieldValues['/attributes/@temail'] || '',
      category: n.fieldValues['/attributes/@tcat'] || 'general',
      note: n.fieldValues['/attributes/note'] || '',
    }));
}

const FILTER_TABS = [
  { id: 'all', label: 'All' },
  { id: 'open', label: 'Open' },
  { id: 'in_progress', label: 'In Progress' },
  { id: 'escalated', label: 'Escalated' },
  { id: 'resolved', label: 'Resolved' },
];

interface NewTicketForm {
  title: string;
  email: string;
  category: string;
  priority: string;
  note: string;
}

export function TicketInbox() {
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [selected, setSelected] = useState<Ticket | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [updating, setUpdating] = useState(false);
  const [form, setForm] = useState<NewTicketForm>({
    title: '', email: '', category: 'technical', priority: 'medium', note: ''
  });

  const fetchTickets = useCallback(async () => {
    try {
      const { data } = await axios.get('/api/taskade/projects/6NuCHBAPtKyXM5pH/nodes');
      if (data.ok) {
        const parsed = parseTickets(data.payload.nodes);
        setTickets(parsed);
        if (selected) {
          const updated = parsed.find((t) => t.id === selected.id);
          if (updated) setSelected(updated);
        }
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }, [selected]);

  useEffect(() => {
    fetchTickets();
  }, []);

  const filtered = filter === 'all' ? tickets : tickets.filter((t) => t.status === filter);

  const counts = {
    open: tickets.filter((t) => t.status === 'open').length,
    escalated: tickets.filter((t) => t.status === 'escalated').length,
    in_progress: tickets.filter((t) => t.status === 'in_progress').length,
  };

  const handleCreate = async () => {
    if (!form.title) return;
    setSubmitting(true);
    try {
      await axios.post('/api/taskade/projects/6NuCHBAPtKyXM5pH/nodes', {
        '/text': form.title,
        '/attributes/@tstat': 'open',
        '/attributes/@tpri': form.priority,
        '/attributes/@temail': form.email,
        '/attributes/@tcat': form.category,
        '/attributes/note': form.note,
      });
      setForm({ title: '', email: '', category: 'technical', priority: 'medium', note: '' });
      setShowForm(false);
      await fetchTickets();
    } catch (e) {
      console.error(e);
    } finally {
      setSubmitting(false);
    }
  };

  const handleUpdateStatus = async (ticketId: string, newStatus: string) => {
    setUpdating(true);
    try {
      await axios.patch(`/api/taskade/projects/6NuCHBAPtKyXM5pH/nodes/${ticketId}`, {
        '/attributes/@tstat': newStatus,
      });
      await fetchTickets();
    } catch (e) {
      console.error(e);
    } finally {
      setUpdating(false);
    }
  };

  if (loading) {
    return (
      <div className="h-full flex items-center justify-center">
        <div className="flex flex-col items-center gap-3 text-white/30">
          <Loader2 className="animate-spin" size={24} />
          <p className="text-sm">Loading tickets...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col">
      {/* Toolbar */}
      <div className="flex items-center justify-between px-6 py-4 border-b border-white/[0.06]">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <Inbox size={16} className="text-violet-400" />
            <h2 className="text-sm font-semibold text-white">Ticket Inbox</h2>
          </div>
          <div className="flex items-center gap-2">
            {counts.open > 0 && (
              <span className="px-2 py-0.5 rounded-full bg-blue-400/10 border border-blue-400/20 text-[10px] text-blue-400 font-medium">
                {counts.open} open
              </span>
            )}
            {counts.escalated > 0 && (
              <span className="px-2 py-0.5 rounded-full bg-red-400/10 border border-red-400/20 text-[10px] text-red-400 font-medium flex items-center gap-1">
                <AlertTriangle size={9} />
                {counts.escalated} escalated
              </span>
            )}
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button
            onClick={fetchTickets}
            className="p-2 rounded-lg border border-white/[0.08] hover:bg-white/[0.05] text-white/40 hover:text-white/70 transition-all"
          >
            <RefreshCw size={13} />
          </button>
          <button
            onClick={() => setShowForm(true)}
            className="flex items-center gap-1.5 px-3 py-2 rounded-lg bg-gradient-to-r from-violet-600 to-cyan-600 text-white text-xs font-medium hover:opacity-90 transition-opacity shadow-md shadow-violet-500/20"
          >
            <Plus size={13} />
            New Ticket
          </button>
        </div>
      </div>

      {/* Filter tabs */}
      <div className="flex gap-1 px-6 pt-3 pb-2 border-b border-white/[0.06]">
        {FILTER_TABS.map((tab) => {
          const count = tab.id === 'all' ? tickets.length : tickets.filter((t) => t.status === tab.id).length;
          return (
            <button
              key={tab.id}
              onClick={() => setFilter(tab.id)}
              className={cn(
                'flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium transition-all',
                filter === tab.id
                  ? 'bg-white/[0.08] text-white border border-white/[0.1]'
                  : 'text-white/40 hover:text-white/70 hover:bg-white/[0.03]'
              )}
            >
              {tab.label}
              {count > 0 && (
                <span className={cn('text-[10px] px-1.5 py-0.5 rounded-full', filter === tab.id ? 'bg-white/[0.1] text-white/70' : 'bg-white/[0.05] text-white/30')}>
                  {count}
                </span>
              )}
            </button>
          );
        })}
      </div>

      {/* Content */}
      <div className="flex flex-1 overflow-hidden">
        {/* Ticket list */}
        <div className={cn('flex flex-col overflow-y-auto border-r border-white/[0.06]', selected ? 'w-2/5' : 'w-full')}>
          {filtered.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 gap-3 text-white/20">
              <Inbox size={32} />
              <p className="text-sm">No tickets found</p>
            </div>
          ) : (
            <div className="divide-y divide-white/[0.04]">
              {filtered.map((ticket) => {
                const statusCfg = STATUS_CONFIG[ticket.status] || STATUS_CONFIG.open;
                const priCfg = PRIORITY_CONFIG[ticket.priority] || PRIORITY_CONFIG.medium;
                const StatusIcon = statusCfg.icon;
                const isSelected = selected?.id === ticket.id;
                return (
                  <button
                    key={ticket.id}
                    onClick={() => setSelected(isSelected ? null : ticket)}
                    className={cn(
                      'w-full text-left px-5 py-4 transition-all hover:bg-white/[0.04]',
                      isSelected && 'bg-white/[0.06] border-l-2 border-violet-500'
                    )}
                  >
                    <div className="flex items-start justify-between gap-3">
                      <div className="min-w-0 flex-1">
                        <p className="text-sm font-medium text-white truncate mb-1.5">{ticket.title}</p>
                        <div className="flex items-center flex-wrap gap-1.5">
                          <span className={cn('inline-flex items-center gap-1 px-2 py-0.5 rounded-full border text-[10px] font-medium', statusCfg.color)}>
                            <StatusIcon size={9} />
                            {statusCfg.label}
                          </span>
                          <span className={cn('text-[10px] font-medium', priCfg.color)}>
                            {priCfg.label}
                          </span>
                          {ticket.category && (
                            <span className="text-[10px] text-white/30 bg-white/[0.04] px-2 py-0.5 rounded-full">
                              {CAT_LABELS[ticket.category] || ticket.category}
                            </span>
                          )}
                        </div>
                        {ticket.email && (
                          <p className="text-[10px] text-white/30 mt-1.5 flex items-center gap-1">
                            <Mail size={9} />
                            {ticket.email}
                          </p>
                        )}
                      </div>
                      <ChevronRight size={14} className={cn('text-white/20 shrink-0 mt-1 transition-transform', isSelected && 'text-violet-400 rotate-90')} />
                    </div>
                  </button>
                );
              })}
            </div>
          )}
        </div>

        {/* Ticket Detail */}
        {selected && (
          <div className="flex-1 overflow-y-auto p-6 space-y-6">
            <div className="flex items-start justify-between">
              <div>
                <h3 className="text-base font-semibold text-white mb-2">{selected.title}</h3>
                <div className="flex flex-wrap gap-2">
                  {(() => {
                    const cfg = STATUS_CONFIG[selected.status] || STATUS_CONFIG.open;
                    const Icon = cfg.icon;
                    return (
                      <span className={cn('inline-flex items-center gap-1 px-2.5 py-1 rounded-full border text-xs font-medium', cfg.color)}>
                        <Icon size={11} />
                        {cfg.label}
                      </span>
                    );
                  })()}
                  <span className={cn('text-xs font-medium px-2.5 py-1 rounded-full bg-white/[0.05]', PRIORITY_CONFIG[selected.priority]?.color)}>
                    {PRIORITY_CONFIG[selected.priority]?.label || 'Medium'} Priority
                  </span>
                  <span className="text-xs text-white/40 bg-white/[0.04] px-2.5 py-1 rounded-full">
                    {CAT_LABELS[selected.category] || selected.category}
                  </span>
                </div>
              </div>
              <button onClick={() => setSelected(null)} className="p-1.5 rounded-lg hover:bg-white/[0.06] text-white/30 hover:text-white/70 transition-all">
                <X size={14} />
              </button>
            </div>

            {selected.email && (
              <div className="flex items-center gap-2 px-3 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.06]">
                <Mail size={13} className="text-white/40" />
                <div>
                  <p className="text-[10px] text-white/30">Customer Email</p>
                  <p className="text-xs text-white/70">{selected.email}</p>
                </div>
              </div>
            )}

            {selected.note && (
              <div className="px-4 py-3 rounded-xl bg-white/[0.03] border border-white/[0.06]">
                <p className="text-[10px] text-white/30 mb-1.5">Description</p>
                <p className="text-sm text-white/70 leading-relaxed">{selected.note}</p>
              </div>
            )}

            {/* Status Actions */}
            <div>
              <p className="text-[10px] text-white/30 mb-2.5 uppercase tracking-wider">Update Status</p>
              <div className="grid grid-cols-2 gap-2">
                {Object.entries(STATUS_CONFIG).map(([key, cfg]) => {
                  const Icon = cfg.icon;
                  const isCurrent = selected.status === key;
                  return (
                    <button
                      key={key}
                      onClick={() => handleUpdateStatus(selected.id, key)}
                      disabled={isCurrent || updating}
                      className={cn(
                        'flex items-center gap-2 px-3 py-2.5 rounded-xl border text-xs font-medium transition-all',
                        isCurrent
                          ? cn(cfg.color, 'opacity-100')
                          : 'border-white/[0.08] bg-white/[0.03] text-white/40 hover:bg-white/[0.07] hover:text-white/70 disabled:opacity-30'
                      )}
                    >
                      {updating && isCurrent ? <Loader2 size={11} className="animate-spin" /> : <Icon size={11} />}
                      {cfg.label}
                    </button>
                  );
                })}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* New Ticket Modal */}
      {showForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="w-full max-w-md bg-[#111118] border border-white/[0.1] rounded-2xl shadow-2xl overflow-hidden">
            <div className="flex items-center justify-between px-5 py-4 border-b border-white/[0.06]">
              <div className="flex items-center gap-2">
