                  >
                    {Object.entries(PRIORITY_CONFIG).map(([k, v]) => <option key={k} value={k}>{v.label}</option>)}
                  </select>
                </div>
              </div>

              <div>
                <label className="text-[10px] text-white/40 uppercase tracking-wider block mb-1.5">Description</label>
                <textarea
                  value={form.note}
                  onChange={(e) => setForm({ ...form, note: e.target.value })}
                  placeholder="Detailed description of the issue..."
                  rows={3}
                  className="w-full px-3 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.08] text-sm text-white placeholder-white/20 outline-none focus:border-violet-500/50 transition-colors resize-none"
                />
              </div>
            </div>

            <div className="flex gap-2 px-5 pb-5">
              <button
                onClick={() => setShowForm(false)}
                className="flex-1 px-4 py-2.5 rounded-xl border border-white/[0.08] text-white/50 hover:text-white/80 text-sm transition-all"
              >
                Cancel
              </button>
              <button
                onClick={handleCreate}
                disabled={!form.title || submitting}
                className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl bg-gradient-to-r from-violet-600 to-cyan-600 text-white text-sm font-medium hover:opacity-90 disabled:opacity-40 transition-all"
              >
                {submitting ? <Loader2 size={14} className="animate-spin" /> : <Send size={14} />}
                {submitting ? 'Creating...' : 'Create Ticket'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import axios from 'axios';
import { cn } from '@/lib/utils';
import {
  BookOpen, Search, ChevronDown, ChevronRight,
  Loader2, ThumbsUp, Clock, CheckCircle, BookMarked,
  HelpCircle, Tag, Sparkles
} from 'lucide-react';

interface KBNode {
  id: string;
  parentId: string | null;
  fieldValues: {
    '/text'?: string;
    '/attributes/@cat01'?: string;
    '/attributes/@helpful'?: number;
    '/attributes/@rcat'?: string;
    '/attributes/@reff'?: string;
    '/attributes/@rtime'?: number;
    '/attributes/note'?: string;
  };
}

interface FAQItem {
  id: string;
  parentId: string | null;
  question: string;
  answer: string;
  category: string;
  helpful: number;
  children: FAQItem[];
}

interface Resolution {
  id: string;
  title: string;
  steps: string;
  category: string;
  effectiveness: string;
  avgTime: number;
}

const CAT_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
  billing: { label: 'Billing', color: 'text-violet-400', bg: 'bg-violet-400/10 border-violet-400/20' },
  technical: { label: 'Technical', color: 'text-cyan-400', bg: 'bg-cyan-400/10 border-cyan-400/20' },
  account: { label: 'Account', color: 'text-emerald-400', bg: 'bg-emerald-400/10 border-emerald-400/20' },
  general: { label: 'General', color: 'text-amber-400', bg: 'bg-amber-400/10 border-amber-400/20' },
  shipping: { label: 'Shipping', color: 'text-orange-400', bg: 'bg-orange-400/10 border-orange-400/20' },
};

const EFF_CONFIG: Record<string, { label: string; color: string }> = {
  proven: { label: 'Proven', color: 'text-emerald-400' },
  experimental: { label: 'Experimental', color: 'text-amber-400' },
  deprecated: { label: 'Deprecated', color: 'text-white/30' },
};

function buildFAQTree(nodes: KBNode[]): FAQItem[] {
  const map = new Map<string, FAQItem>();
  const roots: FAQItem[] = [];

  nodes.forEach((n) => {
    map.set(n.id, {
      id: n.id,
      parentId: n.parentId,
      question: n.fieldValues['/text'] || '',
      answer: '',
      category: n.fieldValues['/attributes/@cat01'] || '',
      helpful: n.fieldValues['/attributes/@helpful'] || 0,
      children: [],
    });
  });

  nodes.forEach((n) => {
    const item = map.get(n.id)!;
    if (n.parentId && map.has(n.parentId)) {
      const parent = map.get(n.parentId)!;
      if (parent.answer === '' && n.fieldValues['/text']) {
        parent.children.push(item);
      }
    } else if (!n.parentId) {
      roots.push(item);
    }
  });

  return roots;
}

function FAQEntry({ item, depth = 0 }: { item: FAQItem; depth?: number }) {
  const [expanded, setExpanded] = useState(false);
  const cat = CAT_CONFIG[item.category];
  const hasChildren = item.children.length > 0;
  const isSection = item.category === '' && depth === 0;

  if (isSection) {
    return (
      <div className="mb-4">
        <h3 className="text-xs font-semibold text-white/40 uppercase tracking-widest mb-2 px-1">{item.question}</h3>
        <div className="space-y-2">
          {item.children.map((child) => (
            <FAQEntry key={child.id} item={child} depth={depth + 1} />
          ))}
        </div>
      </div>
    );
  }

  if (!hasChildren && depth > 0) {
    return (
      <div className="px-3 py-2.5 rounded-lg bg-white/[0.03] text-sm text-white/60 leading-relaxed">
        {item.question}
      </div>
    );
  }

  return (
    <div className={cn('rounded-xl border overflow-hidden transition-all', expanded ? 'border-white/[0.12] bg-white/[0.04]' : 'border-white/[0.06] bg-white/[0.02] hover:bg-white/[0.04] hover:border-white/[0.1]')}>
      <button
        onClick={() => hasChildren && setExpanded(!expanded)}
        className="w-full text-left px-4 py-3.5 flex items-center gap-3"
      >
        <div className="flex-1 min-w-0">
          <div className="flex items-start gap-2 mb-1">
            {cat && (
              <span className={cn('px-2 py-0.5 rounded-full border text-[10px] font-medium shrink-0 mt-0.5', cat.bg, cat.color)}>
                {cat.label}
              </span>
            )}
            <p className={cn('text-sm font-medium leading-snug', expanded ? 'text-white' : 'text-white/80')}>{item.question}</p>
          </div>
          {item.helpful > 0 && (
            <p className="text-[10px] text-white/25 flex items-center gap-1 pl-0">
              <ThumbsUp size={9} />
              {item.helpful} found helpful
            </p>
          )}
        </div>
        {hasChildren && (
          <ChevronDown size={14} className={cn('text-white/30 shrink-0 transition-transform', expanded && 'rotate-180')} />
        )}
      </button>

      {expanded && item.children.length > 0 && (
        <div className="px-4 pb-4 space-y-1.5 border-t border-white/[0.06]">
          <div className="pt-3 space-y-1.5">
            {item.children.map((child) => (
              <FAQEntry key={child.id} item={child} depth={depth + 1} />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

export function KnowledgeBase() {
  const [faqNodes, setFaqNodes] = useState<KBNode[]>([]);
  const [resNodes, setResNodes] = useState<KBNode[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [catFilter, setCatFilter] = useState('all');
  const [activeSection, setActiveSection] = useState<'faqs' | 'resolutions'>('faqs');

  useEffect(() => {
    const fetchAll = async () => {
      try {
        const [faqRes, resRes] = await Promise.all([
          axios.get('/api/taskade/projects/i8FQRPsSe5fTEXNz/nodes'),
          axios.get('/api/taskade/projects/grC1rXxwT3mb7Tnj/nodes'),
        ]);
        if (faqRes.data.ok) setFaqNodes(faqRes.data.payload.nodes);
        if (resRes.data.ok) setResNodes(resRes.data.payload.nodes);
      } catch (e) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    };
    fetchAll();
  }, []);

  const faqTree = useMemo(() => buildFAQTree(faqNodes), [faqNodes]);

  const resolutions: Resolution[] = useMemo(() => {
    return resNodes
      .filter((n) => n.parentId === null && n.fieldValues['/text'])
      .map((n) => {
        const stepNode = resNodes.find((c) => c.parentId === n.id);
        return {
          id: n.id,
          title: n.fieldValues['/text'] || '',
          steps: stepNode?.fieldValues['/text'] || '',
          category: n.fieldValues['/attributes/@rcat'] || 'general',
          effectiveness: n.fieldValues['/attributes/@reff'] || 'proven',
          avgTime: n.fieldValues['/attributes/@rtime'] || 0,
        };
      });
  }, [resNodes]);

  const filteredResolutions = useMemo(() => {
    return resolutions.filter((r) => {
      const matchesCat = catFilter === 'all' || r.category === catFilter;
      const matchesSearch = !search || r.title.toLowerCase().includes(search.toLowerCase()) || r.steps.toLowerCase().includes(search.toLowerCase());
      return matchesCat && matchesSearch;
    });
  }, [resolutions, catFilter, search]);

  const filteredFAQs = useMemo(() => {
    if (!search) return faqTree;
    const searchLower = search.toLowerCase();
    const filterItems = (items: FAQItem[]): FAQItem[] => {
      return items.reduce<FAQItem[]>((acc, item) => {
        const matches = item.question.toLowerCase().includes(searchLower);
        const filteredChildren = filterItems(item.children);
        if (matches || filteredChildren.length > 0) {
          acc.push({ ...item, children: filteredChildren });
        }
        return acc;
      }, []);
    };
    return filterItems(faqTree);
  }, [faqTree, search]);

  if (loading) {
    return (
      <div className="h-full flex items-center justify-center">
        <div className="flex flex-col items-center gap-3 text-white/30">
          <Loader2 className="animate-spin" size={24} />
          <p className="text-sm">Loading knowledge base...</p>
        </div>
      </div>
    );
  }

  const cats = ['all', 'billing', 'technical', 'account', 'general', 'shipping'];

  return (
    <div className="max-w-3xl mx-auto px-6 py-6 space-y-6">
      {/* Header */}
      <div>
        <div className="flex items-center gap-2 mb-1">
          <BookOpen size={16} className="text-violet-400" />
          <h2 className="text-sm font-semibold text-white">Knowledge Base</h2>
        </div>
        <p className="text-xs text-white/30">FAQs, resolution guides, and support documentation</p>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-3 gap-3">
        <div className="px-4 py-3 rounded-xl bg-white/[0.03] border border-white/[0.06]">
          <p className="text-xl font-bold text-white">{faqNodes.filter((n) => n.fieldValues['/attributes/@cat01']).length}</p>
          <p className="text-[10px] text-white/30 mt-0.5">FAQ Entries</p>
        </div>
        <div className="px-4 py-3 rounded-xl bg-white/[0.03] border border-white/[0.06]">
          <p className="text-xl font-bold text-white">{resolutions.length}</p>
          <p className="text-[10px] text-white/30 mt-0.5">Resolution Guides</p>
        </div>
        <div className="px-4 py-3 rounded-xl bg-white/[0.03] border border-white/[0.06]">
          <p className="text-xl font-bold text-white">{resolutions.filter((r) => r.effectiveness === 'proven').length}</p>
          <p className="text-[10px] text-white/30 mt-0.5">Proven Solutions</p>
        </div>
      </div>

      {/* Search */}
      <div className="relative">
        <Search size={14} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-white/30" />
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search knowledge base..."
          className="w-full pl-9 pr-4 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.08] text-sm text-white placeholder-white/20 outline-none focus:border-violet-500/40 transition-colors"
        />
      </div>

      {/* Section Tabs */}
      <div className="flex gap-2">
        <button
          onClick={() => setActiveSection('faqs')}
          className={cn(
            'flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-medium transition-all',
            activeSection === 'faqs'
              ? 'bg-white/[0.08] text-white border border-white/[0.1]'
              : 'text-white/40 hover:text-white/70 hover:bg-white/[0.04]'
          )}
        >
          <HelpCircle size={13} />
          FAQs
          <span className="text-[10px] px-1.5 py-0.5 rounded-full bg-white/[0.1] text-white/60">{faqNodes.filter((n) => n.fieldValues['/attributes/@cat01']).length}</span>
        </button>
        <button
          onClick={() => setActiveSection('resolutions')}
          className={cn(
            'flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-medium transition-all',
            activeSection === 'resolutions'
              ? 'bg-white/[0.08] text-white border border-white/[0.1]'
              : 'text-white/40 hover:text-white/70 hover:bg-white/[0.04]'
          )}
        >
          <BookMarked size={13} />
          Resolutions
          <span className="text-[10px] px-1.5 py-0.5 rounded-full bg-white/[0.1] text-white/60">{resolutions.length}</span>
        </button>
      </div>

      {/* Category filter (for resolutions) */}
      {activeSection === 'resolutions' && (
        <div className="flex flex-wrap gap-1.5">
          {cats.map((cat) => {
            const cfg = CAT_CONFIG[cat];
            return (
              <button
                key={cat}
                onClick={() => setCatFilter(cat)}
                className={cn(
                  'px-3 py-1.5 rounded-lg text-xs font-medium transition-all',
                  catFilter === cat
                    ? 'bg-white/[0.1] text-white border border-white/[0.15]'
                    : 'text-white/40 hover:text-white/70 hover:bg-white/[0.04]'
                )}
              >
                {cat === 'all' ? 'All Categories' : cfg?.label || cat}
              </button>
            );
          })}
        </div>
      )}

      {/* FAQs Section */}
      {activeSection === 'faqs' && (
        <div className="space-y-3">
          {filteredFAQs.length === 0 ? (
            <div className="text-center py-12 text-white/20">
              <HelpCircle size={32} className="mx-auto mb-3" />
              <p className="text-sm">No FAQs match your search</p>
            </div>
          ) : (
            filteredFAQs.map((item) => (
              <FAQEntry key={item.id} item={item} />
            ))
          )}
        </div>
      )}

      {/* Resolutions Section */}
      {activeSection === 'resolutions' && (
        <div className="space-y-3">
          {filteredResolutions.length === 0 ? (
            <div className="text-center py-12 text-white/20">
              <BookMarked size={32} className="mx-auto mb-3" />
              <p className="text-sm">No resolutions match your filters</p>
            </div>
          ) : (
            filteredResolutions.map((res) => {
              const cat = CAT_CONFIG[res.category];
              const eff = EFF_CONFIG[res.effectiveness] || EFF_CONFIG.proven;
              return (
                <ResolutionCard key={res.id} res={res} cat={cat} eff={eff} />
              );
            })
          )}
        </div>
      )}
    </div>
  );
}

function ResolutionCard({ res, cat, eff }: {
  res: Resolution;
  cat?: { label: string; color: string; bg: string };
  eff: { label: string; color: string };
}) {
  const [expanded, setExpanded] = useState(false);

  return (
    <div className={cn('rounded-xl border overflow-hidden transition-all', expanded ? 'border-white/[0.12] bg-white/[0.04]' : 'border-white/[0.06] bg-white/[0.02] hover:bg-white/[0.04] hover:border-white/[0.1]')}>
      <button
        onClick={() => setExpanded(!expanded)}
        className="w-full text-left px-4 py-3.5 flex items-start gap-3"
      >
        <div className="flex-1 min-w-0">
          <div className="flex flex-wrap items-center gap-2 mb-1.5">
            {cat && (
              <span className={cn('px-2 py-0.5 rounded-full border text-[10px] font-medium', cat.bg, cat.color)}>
                {cat.label}
              </span>
            )}
            <span className={cn('text-[10px] font-medium flex items-center gap-1', eff.color)}>
              <CheckCircle size={9} />
              {eff.label}
            </span>
            {res.avgTime > 0 && (
              <span className="text-[10px] text-white/25 flex items-center gap-1">
                <Clock size={9} />
                ~{res.avgTime} min
              </span>
            )}
          </div>
          <p className={cn('text-sm font-medium', expanded ? 'text-white' : 'text-white/80')}>{res.title}</p>
        </div>
        <ChevronDown size={14} className={cn('text-white/30 shrink-0 mt-1 transition-transform', expanded && 'rotate-180')} />
      </button>

      {expanded && res.steps && (
        <div className="px-4 pb-4 border-t border-white/[0.06]">
          <div className="pt-3">
            <div className="flex items-center gap-1.5 mb-2">
              <Sparkles size={11} className="text-violet-400" />
              <p className="text-[10px] text-white/40 uppercase tracking-wider">Resolution Steps</p>
            </div>
            <div className="space-y-2">
              {res.steps.split(/Step \d+:/i).filter(Boolean).map((step, i) => (
                <div key={i} className="flex gap-2.5">
                  <div className="w-5 h-5 rounded-full bg-violet-500/20 border border-violet-500/30 flex items-center justify-center shrink-0 mt-0.5">
                    <span className="text-[9px] text-violet-400 font-bold">{i + 1}</span>
                  </div>
                  <p className="text-xs text-white/60 leading-relaxed pt-0.5">{step.trim()}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
